import { createBrowserRouter, Navigate } from 'react-router-dom';
import { lazy, Suspense } from 'react';
import { DashboardLayout } from '@/layouts/DashboardLayout';
import { AuthLayout } from '@/layouts/AuthLayout';
import { ProtectedRoute } from '@/shared/components/ProtectedRoute';
import { PageLoader } from '@/shared/components/PageLoader';
import { ErrorBoundaryPage } from '@/shared/components/ErrorBoundaryPage';

// ─── Lazy-loaded pages ────────────────────────────────────────────────────────

const LoginPage = lazy(() => import('@/features/auth/pages/LoginPage'));
const RegisterPage = lazy(() => import('@/features/auth/pages/RegisterPage'));
const OtpPage = lazy(() => import('@/features/auth/pages/OtpPage'));
const OnboardingPage = lazy(() => import('@/features/onboarding/pages/OnboardingPage'));

const WorkerDashboard = lazy(() => import('@/features/dashboard/pages/WorkerDashboard'));
const EmployerDashboard = lazy(() => import('@/features/dashboard/pages/EmployerDashboard'));
const RecruiterDashboard = lazy(() => import('@/features/dashboard/pages/RecruiterDashboard'));
const AdminDashboard = lazy(() => import('@/features/dashboard/pages/AdminDashboard'));

const JobsListPage = lazy(() => import('@/features/jobs/pages/JobsListPage'));
const JobDetailPage = lazy(() => import('@/features/jobs/pages/JobDetailPage'));
const PostJobPage = lazy(() => import('@/features/jobs/pages/PostJobPage'));
const ActiveShiftPage = lazy(() => import('@/features/jobs/pages/ActiveShiftPage'));
const JobApplicationsPage = lazy(() => import('@/features/applications/pages/JobApplicationsPage'));

const MessagesPage = lazy(() => import('@/features/messaging/pages/MessagesPage'));
const MessagingPage = lazy(() =>
  import('@/features/messaging/pages/MessagingPage').then((module) => ({
    default: module.MessagingPage,
  })),
);

const ProfilePage = lazy(() => import('@/features/profile/pages/ProfilePage'));
const WalletPage = lazy(() => import('@/features/wallet/pages/WalletPage'));
const SettingsPage = lazy(() => import('@/features/settings/pages/SettingsPage'));
const VerificationPage = lazy(() => import('@/features/kyc/pages/VerificationPage'));
const NotificationsPage = lazy(() => import('@/features/notifications/pages/NotificationsPage'));

const ManageJobsPage = lazy(() => import('@/features/jobs/pages/ManageJobsPage'));
const RequisitionsPage = lazy(() => import('@/features/jobs/pages/RequisitionsPage'));
const MyApplicationsPage = lazy(() => import('@/features/applications/pages/MyApplicationsPage'));
const ApplicantsPage = lazy(() => import('@/features/applications/pages/ApplicantsPage'));
const CandidatesPage = lazy(() => import('@/features/candidates/pages/CandidatesPage'));
const InterviewsPage = lazy(() => import('@/features/interviews/pages/InterviewsPage'));
const TimesheetsPage = lazy(() => import('@/features/timesheets/pages/TimesheetsPage'));
const TimesheetApprovalPage = lazy(() =>
  import('@/features/timesheets/pages/TimesheetApprovalPage').then((module) => ({
    default: module.TimesheetApprovalPage,
  })),
);
const BillingPage = lazy(() => import('@/features/billing/pages/BillingPage'));
const UsersManagementPage = lazy(() => import('@/features/admin/pages/UsersManagementPage'));
const PlatformAnalyticsPage = lazy(() => import('@/features/admin/pages/PlatformAnalyticsPage'));
const SystemLogsPage = lazy(() => import('@/features/admin/pages/SystemLogsPage'));
const FinancialsPage = lazy(() => import('@/features/admin/pages/FinancialsPage'));
const HelpCenterPage = lazy(() => import('@/features/help/pages/HelpCenterPage'));

const wrap = (Component: any) => (
  <Suspense fallback={<PageLoader fullScreen={false} />}>
    <Component />
  </Suspense>
);

export const router = createBrowserRouter([
  // ─── Auth routes (public) ──────────────────────────────────────────────
  {
    element: <AuthLayout />,
    errorElement: <ErrorBoundaryPage />,
    children: [
      { path: '/login', element: wrap(LoginPage) },
      { path: '/register', element: wrap(RegisterPage) },
      { path: '/verify-otp', element: wrap(OtpPage) },
    ],
  },

  // ─── Onboarding (authenticated, no shell) ─────────────────────────────
  {
    path: '/onboarding',
    element: <ProtectedRoute>{wrap(OnboardingPage)}</ProtectedRoute>,
  },

  // ─── Main application shell ────────────────────────────────────────────
  {
    element: (
      <ProtectedRoute>
        <DashboardLayout />
      </ProtectedRoute>
    ),
    errorElement: <ErrorBoundaryPage />,
    children: [
      { path: '/', element: <Navigate to="/dashboard" replace /> },
      { path: '/dashboard', element: <Navigate to="/dashboard/worker" replace /> },
      { path: '/dashboard/worker', element: wrap(WorkerDashboard) },
      { path: '/dashboard/employer', element: wrap(EmployerDashboard) },
      { path: '/dashboard/recruiter', element: wrap(RecruiterDashboard) },
      { path: '/dashboard/admin', element: wrap(AdminDashboard) },
      { path: '/jobs', element: wrap(JobsListPage) },
      { path: '/jobs/:id', element: wrap(JobDetailPage) },
      { path: '/shifts/:id', element: wrap(ActiveShiftPage) },
      { path: '/jobs/:id/applications', element: wrap(JobApplicationsPage) },
      { path: '/jobs/post', element: wrap(PostJobPage) },
      { path: '/jobs/manage', element: wrap(ManageJobsPage) },
      { path: '/jobs/requisitions', element: wrap(RequisitionsPage) },
      { path: '/applications/my', element: wrap(MyApplicationsPage) },
      { path: '/applicants', element: wrap(ApplicantsPage) },
      { path: '/candidates', element: wrap(CandidatesPage) },
      { path: '/interviews', element: wrap(InterviewsPage) },
      { path: '/timesheets', element: wrap(TimesheetsPage) },
      { path: '/billing', element: wrap(BillingPage) },
      { path: '/admin/users', element: wrap(UsersManagementPage) },
      { path: '/admin/analytics', element: wrap(PlatformAnalyticsPage) },
      { path: '/admin/logs', element: wrap(SystemLogsPage) },
      { path: '/admin/financials', element: wrap(FinancialsPage) },
      { path: '/messages', element: wrap(MessagesPage) },
      { path: '/chat', element: wrap(MessagingPage) },
      { path: '/timesheet-approvals', element: wrap(TimesheetApprovalPage) },
      { path: '/profile/:role/:id', element: wrap(ProfilePage) },
      { path: '/wallet', element: wrap(WalletPage) },
      { path: '/verification', element: wrap(VerificationPage) },
      { path: '/settings', element: wrap(SettingsPage) },
      { path: '/notifications', element: wrap(NotificationsPage) },
      { path: '/help', element: wrap(HelpCenterPage) },
      { path: '*', element: <Navigate to="/dashboard" replace /> },
    ],
  },
]);

import api from '@/shared/lib/api';

export interface AdminDashboardStats {
  activeUsers: number;
  jobsProcessed: number;
  pendingKyc: number;
  isApiHealthy: boolean;
}

export const adminApi = {
  getDashboardStats: async (): Promise<AdminDashboardStats> => {
    const response = await api.get('/admin/stats');
    return response.data;
  },
};

import api from '@/shared/lib/api';

export const analyticsApi = {
  getStats: async (): Promise<any> => {
    const { data } = await api.get('/analytics/stats');
    return data;
  },

  getRevenue: async (): Promise<any[]> => {
    const { data } = await api.get('/analytics/revenue');
    return data;
  },
};

import api from '@/shared/lib/api';

export const auditApi = {
  getLogs: async (): Promise<any[]> => {
    const { data } = await api.get('/audit/logs');
    return data;
  },
};

import React from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  Legend,
} from 'recharts';
import { Users, Briefcase, Activity, TrendingUp } from 'lucide-react';
import { analyticsApi } from '../api/analytics.api';

export default function PlatformAnalyticsPage(): React.ReactElement {
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
    queryKey: ['analytics-stats'],
    queryFn: analyticsApi.getStats,
  });

  const { data: revenueData = [], isLoading: isRevenueLoading } = useQuery({
    queryKey: ['analytics-revenue'],
    queryFn: analyticsApi.getRevenue,
  });

  const jobCategoryData = [
    { name: 'Warehouse', jobs: 420 },
    { name: 'Delivery', jobs: 380 },
    { name: 'Tech', jobs: 250 },
    { name: 'Retail', jobs: 190 },
    { name: 'Admin', jobs: 140 },
  ];

  const stats = [
    {
      label: 'Total Active Users',
      value: statsData?.totalUsers || 0,
      change: statsData?.activeUsersGrowth || '0%',
      icon: Users,
      color: 'text-blue-500',
    },
    {
      label: 'Active Job Postings',
      value: statsData?.activeJobs || 0,
      change: statsData?.jobsGrowth || '0%',
      icon: Briefcase,
      color: 'text-purple-500',
    },
    {
      label: 'Completed Shifts',
      value: statsData?.completedShifts || 0,
      change: statsData?.shiftsGrowth || '0%',
      icon: TrendingUp,
      color: 'text-green-500',
    },
    {
      label: 'Gross Volume',
      value: `₹${statsData?.grossPaymentVolume?.toLocaleString() || 0}`,
      change: statsData?.volumeGrowth || '0%',
      icon: Activity,
      color: 'text-amber-500',
    },
  ];

  if (isStatsLoading || isRevenueLoading) {
    return <div className="p-12 text-center text-muted-foreground">Loading analytics...</div>;
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight text-foreground">Platform Analytics</h1>
        <p className="mt-1 text-muted-foreground">
          High-level metrics and growth trends across Shiftly.
        </p>
      </div>

      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4">
        {stats.map((stat, i) => {
          const Icon = stat.icon;
          return (
            <div key={i} className="rounded-xl border border-border bg-card p-5 shadow-sm">
              <div className="flex items-start justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">{stat.label}</p>
                  <h3 className="mt-1 text-2xl font-bold text-foreground">{stat.value}</h3>
                </div>
                <div className={`rounded-lg bg-muted p-2 ${stat.color}`}>
                  <Icon className="h-5 w-5" />
                </div>
              </div>
              <div className="mt-4 flex items-center text-sm">
                <span className="font-medium text-green-500">{stat.change}</span>
                <span className="ml-2 text-muted-foreground">vs last month</span>
              </div>
            </div>
          );
        })}
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* Main Growth Chart */}
        <div className="rounded-xl border border-border bg-card p-5 shadow-sm lg:col-span-2">
          <h2 className="mb-4 text-lg font-semibold text-foreground">
            Revenue Growth Trend (Gross Volume)
          </h2>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={revenueData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#333" opacity={0.2} vertical={false} />
                <XAxis
                  dataKey="name"
                  stroke="#888"
                  fontSize={12}
                  tickLine={false}
                  axisLine={false}
                />
                <YAxis stroke="#888" fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'hsl(var(--card))',
                    borderColor: 'hsl(var(--border))',
                    borderRadius: '8px',
                  }}
                  itemStyle={{ color: 'hsl(var(--foreground))' }}
                />
                <Legend />
                <Area
                  type="monotone"
                  dataKey="value"
                  stroke="#10b981"
                  strokeWidth={2}
                  fillOpacity={1}
                  fill="url(#colorValue)"
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Jobs Category Bar Chart */}
        <div className="rounded-xl border border-border bg-card p-5 shadow-sm">
          <h2 className="mb-4 text-lg font-semibold text-foreground">Top Categories</h2>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={jobCategoryData}
                layout="vertical"
                margin={{ top: 0, right: 0, left: 10, bottom: 0 }}
              >
                <CartesianGrid
                  strokeDasharray="3 3"
                  stroke="#333"
                  opacity={0.1}
                  horizontal={true}
                  vertical={false}
                />
                <XAxis type="number" hide />
                <YAxis
                  dataKey="name"
                  type="category"
                  stroke="#888"
                  fontSize={12}
                  tickLine={false}
                  axisLine={false}
                />
                <Tooltip
                  cursor={{ fill: 'rgba(255, 255, 255, 0.05)' }}
                  contentStyle={{
                    backgroundColor: 'hsl(var(--card))',
                    borderColor: 'hsl(var(--border))',
                    borderRadius: '8px',
                  }}
                />
                <Bar dataKey="jobs" fill="#10b981" radius={[0, 4, 4, 0]} barSize={24} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { ShieldAlert, Info, AlertTriangle, Terminal, Filter, RefreshCw } from 'lucide-react';
import { auditApi } from '../api/audit.api';

export default function SystemLogsPage(): React.ReactElement {
  const {
    data: logs = [],
    isLoading,
    refetch,
  } = useQuery({
    queryKey: ['system-logs'],
    queryFn: auditApi.getLogs,
  });

  const getLevelStyle = (level: string) => {
    switch (level) {
      case 'CRITICAL':
        return { icon: ShieldAlert, color: 'text-red-500', bg: 'bg-red-500/10 border-red-500/20' };
      case 'ERROR':
        return {
          icon: AlertTriangle,
          color: 'text-orange-500',
          bg: 'bg-orange-500/10 border-orange-500/20',
        };
      case 'WARNING':
        return {
          icon: AlertTriangle,
          color: 'text-amber-500',
          bg: 'bg-amber-500/10 border-amber-500/20',
        };
      default:
        return { icon: Info, color: 'text-blue-500', bg: 'bg-blue-500/10 border-blue-500/20' };
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col justify-between gap-4 md:flex-row md:items-center">
        <div>
          <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight text-foreground">
            <Terminal className="h-6 w-6 text-muted-foreground" /> System Logs
          </h1>
          <p className="mt-1 text-muted-foreground">
            Real-time infrastructure and application events.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center justify-center gap-2 rounded-lg bg-muted px-4 py-2 font-medium text-foreground transition-colors hover:bg-muted/80">
            <Filter className="h-4 w-4" /> Filter Logs
          </button>
          <button
            onClick={() => refetch()}
            className="flex items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2 font-medium text-primary-foreground transition-colors hover:bg-primary/90"
          >
            <RefreshCw className="h-4 w-4" /> Refresh Logs
          </button>
        </div>
      </div>

      <div className="overflow-hidden rounded-xl border border-border bg-card font-mono text-sm shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full border-collapse text-left">
            <thead>
              <tr className="border-b border-border bg-muted/30 text-muted-foreground">
                <th className="p-4 font-medium">Timestamp</th>
                <th className="p-4 font-medium">Level</th>
                <th className="p-4 font-medium">Service</th>
                <th className="p-4 font-medium">Message</th>
                <th className="p-4 font-medium">Source IP</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {isLoading ? (
                <tr>
                  <td colSpan={5} className="p-4 text-center text-muted-foreground">
                    Loading logs...
                  </td>
                </tr>
              ) : logs.length === 0 ? (
                <tr>
                  <td colSpan={5} className="p-4 text-center text-muted-foreground">
                    No logs found.
                  </td>
                </tr>
              ) : (
                logs.map((log: any) => {
                  const style = getLevelStyle(log.severity);
                  const Icon = style.icon;
                  return (
                    <tr key={log.id} className="transition-colors hover:bg-muted/10">
                      <td className="whitespace-nowrap p-4 text-muted-foreground">
                        {new Date(log.timestamp).toLocaleString()}
                      </td>
                      <td className="p-4">
                        <div
                          className={`inline-flex items-center gap-1.5 rounded-md border px-2 py-1 ${style.bg} ${style.color}`}
                        >
                          <Icon className="h-3.5 w-3.5" />
                          <span className="text-xs font-semibold tracking-wider">
                            {log.severity}
                          </span>
                        </div>
                      </td>
                      <td className="p-4 font-medium text-primary/80">
                        {log.actorEmail || 'System'}
                      </td>
                      <td className="p-4 text-foreground">
                        {log.action} - {log.target}
                      </td>
                      <td className="p-4 text-muted-foreground">{log.ip || 'Internal'}</td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { applicationsApi } from '../../jobs/api/applications.api';
import type { JobApplication } from '../../jobs/api/applications.api';
import { User, Star, Briefcase, BookmarkPlus, Check, X, Filter } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';

type ApplicationStatus =
  'PENDING' | 'SHORTLISTED' | 'ACCEPTED' | 'REJECTED' | 'WITHDRAWN' | 'COMPLETED';

export default function JobApplicationsPage(): React.ReactElement {
  const { id } = useParams<{ id: string }>();

  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Status filter state
  const [statusFilter, setStatusFilter] = useState<ApplicationStatus | 'ALL'>('ALL');
  // For updating status dropdown
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  useEffect(() => {
    if (!id) return;

    const fetchApps = async () => {
      try {
        setIsLoading(true);
        const data = await applicationsApi.getApplicationsForJob(id);
        setApplications(data.items);
      } catch (err) {
        console.error('Failed to load applications.', err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchApps();
  }, [id]);

  const handleUpdateStatus = async (applicationId: string, newStatus: ApplicationStatus) => {
    try {
      setUpdatingId(applicationId);
      const updatedApp = await applicationsApi.updateApplicationStatus(applicationId, {
        status: newStatus,
      });
      setApplications((prev) => prev.map((app) => (app.id === applicationId ? updatedApp : app)));
    } catch (err) {
      alert('Failed to update status');
    } finally {
      setUpdatingId(null);
    }
  };

  const filteredApplications = applications.filter(
    (app) => statusFilter === 'ALL' || app.status === statusFilter,
  );

  const getStatusBadgeColor = (status: string) => {
    switch (status) {
      case 'PENDING':
        return 'bg-yellow-500/10 text-yellow-600 border-yellow-500/20';
      case 'SHORTLISTED':
        return 'bg-blue-500/10 text-blue-600 border-blue-500/20';
      case 'ACCEPTED':
        return 'bg-green-500/10 text-green-600 border-green-500/20';
      case 'REJECTED':
        return 'bg-red-500/10 text-red-600 border-red-500/20';
      case 'WITHDRAWN':
        return 'bg-gray-500/10 text-gray-600 border-gray-500/20';
      case 'COMPLETED':
        return 'bg-purple-500/10 text-purple-600 border-purple-500/20';
      default:
        return 'bg-muted text-muted-foreground border-border';
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="h-8 w-8 animate-spin rounded-full border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="mx-auto max-w-5xl space-y-6">
      <div className="flex flex-col items-start justify-between gap-4 md:flex-row md:items-center">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-foreground">Applications</h1>
          <p className="mt-1 text-muted-foreground">Manage candidates for this job posting.</p>
        </div>

        <div className="flex items-center gap-2 rounded-md border border-input bg-card p-1">
          <Filter className="ml-2 h-4 w-4 text-muted-foreground" />
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value as ApplicationStatus | 'ALL')}
            className="cursor-pointer border-none bg-transparent py-1.5 pr-8 text-sm font-medium text-foreground outline-none focus:ring-0"
          >
            <option value="ALL">All Statuses</option>
            <option value="PENDING">Pending</option>
            <option value="SHORTLISTED">Shortlisted</option>
            <option value="ACCEPTED">Accepted</option>
            <option value="REJECTED">Rejected</option>
          </select>
        </div>
      </div>

      <div className="overflow-hidden rounded-xl border border-border bg-card shadow-sm">
        {filteredApplications.length === 0 ? (
          <div className="py-16 text-center">
            <User className="mx-auto mb-4 h-12 w-12 text-muted-foreground opacity-50" />
            <h3 className="text-lg font-medium text-foreground">No applications found</h3>
            <p className="text-muted-foreground">
              There are no candidates matching the selected filter.
            </p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-muted/50 text-xs uppercase text-muted-foreground">
                <tr>
                  <th className="px-6 py-4 font-medium">Candidate</th>
                  <th className="px-6 py-4 font-medium">Experience</th>
                  <th className="px-6 py-4 font-medium">Applied</th>
                  <th className="px-6 py-4 font-medium">Status</th>
                  <th className="px-6 py-4 text-right font-medium">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                <AnimatePresence>
                  {filteredApplications.map((app) => (
                    <motion.tr
                      key={app.id}
                      layout
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      exit={{ opacity: 0 }}
                      className="transition-colors hover:bg-muted/30"
                    >
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          {app.worker?.avatarUrl ? (
                            <img
                              src={app.worker.avatarUrl}
                              alt=""
                              className="h-10 w-10 rounded-full object-cover"
                            />
                          ) : (
                            <div className="flex h-10 w-10 items-center justify-center rounded-full bg-primary/20 font-bold text-primary">
                              {app.worker?.firstName?.charAt(0)}
                              {app.worker?.lastName?.charAt(0)}
                            </div>
                          )}
                          <div>
                            <span className="block font-medium text-foreground">
                              {app.worker?.firstName} {app.worker?.lastName}
                            </span>
                            <div className="mt-0.5 flex items-center text-xs text-muted-foreground">
                              <Star className="mr-1 h-3 w-3 text-yellow-500" />
                              {app.worker?.rating || 0}
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-muted-foreground">
                          <Briefcase className="mr-2 h-4 w-4" />
                          {app.worker?.experienceYears || 0} Years
                        </div>
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        {new Date(app.appliedAt).toLocaleDateString()}
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex items-center rounded-md border px-2.5 py-1 text-xs font-semibold ${getStatusBadgeColor(app.status)}`}
                        >
                          {app.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        {updatingId === app.id ? (
                          <div className="mr-4 inline-block h-4 w-4 animate-spin rounded-full border-b-2 border-primary"></div>
                        ) : (
                          <div className="flex justify-end gap-2">
                            {app.status === 'PENDING' && (
                              <>
                                <button
                                  onClick={() => handleUpdateStatus(app.id, 'SHORTLISTED')}
                                  className="flex items-center gap-1.5 rounded-md border border-blue-500/20 bg-blue-500/10 px-2.5 py-1.5 text-xs font-medium text-blue-500 transition-colors hover:bg-blue-500/20"
                                  title="Shortlist candidate"
                                >
                                  <BookmarkPlus className="h-3.5 w-3.5" /> Shortlist
                                </button>
                                <button
                                  onClick={() => handleUpdateStatus(app.id, 'REJECTED')}
                                  className="flex items-center gap-1.5 rounded-md border border-red-500/20 bg-red-500/10 px-2.5 py-1.5 text-xs font-medium text-red-500 transition-colors hover:bg-red-500/20"
                                  title="Reject candidate"
                                >
                                  <X className="h-3.5 w-3.5" /> Reject
                                </button>
                              </>
                            )}
                            {app.status === 'SHORTLISTED' && (
                              <>
                                <button
                                  onClick={() => handleUpdateStatus(app.id, 'ACCEPTED')}
                                  className="flex items-center gap-1.5 rounded-md border border-green-500/20 bg-green-500/10 px-2.5 py-1.5 text-xs font-medium text-green-500 transition-colors hover:bg-green-500/20"
                                  title="Accept candidate"
                                >
                                  <Check className="h-3.5 w-3.5" /> Accept
                                </button>
                                <button
                                  onClick={() => handleUpdateStatus(app.id, 'REJECTED')}
                                  className="flex items-center gap-1.5 rounded-md border border-red-500/20 bg-red-500/10 px-2.5 py-1.5 text-xs font-medium text-red-500 transition-colors hover:bg-red-500/20"
                                  title="Reject candidate"
                                >
                                  <X className="h-3.5 w-3.5" /> Reject
                                </button>
                              </>
                            )}
                            {['ACCEPTED', 'REJECTED', 'WITHDRAWN', 'COMPLETED'].includes(
                              app.status,
                            ) && (
                              <button
                                className="text-sm font-medium text-primary hover:underline"
                                onClick={() => alert('View full profile functionality coming soon')}
                              >
                                View Profile
                              </button>
                            )}
                          </div>
                        )}
                      </td>
                    </motion.tr>
                  ))}
                </AnimatePresence>
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import {
  Briefcase,
  Building,
  MapPin,
