import React, { useState } from 'react';
import { useNavigate, Link, useLocation } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { motion, AnimatePresence } from 'framer-motion';
import { Phone, Mail, Eye, EyeOff, Loader2, ArrowRight } from 'lucide-react';
import { z } from 'zod';
import { useAppDispatch } from '@/app/store';
import { setUser } from '../store/authSlice';
import { authApi } from '../api/auth.api';
import { setAccessToken } from '@/shared/lib/api';
import { jwtDecode } from '../utils/jwt';
import type { JwtPayload } from '@shiftly/shared-types';

// ─── Form schemas ──────────────────────────────────────────────────────────────

const phoneSchema = z.object({
  phone: z
    .string()
    .min(10, 'Enter a valid phone number')
    .regex(/^\+?[1-9]\d{9,14}$/, 'Enter phone with country code (e.g. +91...)'),
});

const emailSchema = z.object({
  email: z.string().email('Enter a valid email address'),
  password: z.string().min(1, 'Password is required'),
});

type PhoneForm = z.infer<typeof phoneSchema>;
type EmailForm = z.infer<typeof emailSchema>;
type LoginMode = 'phone' | 'email';

// ─── Component ─────────────────────────────────────────────────────────────────

export default function LoginPage(): React.ReactElement {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const [mode, setMode] = useState<LoginMode>('phone');
  const [showPassword, setShowPassword] = useState(false);
  const from = (location.state as { from?: { pathname: string } })?.from?.pathname ?? '/dashboard';

  // ─── Phone form ──────────────────────────────────────────────────────
  const phoneForm = useForm<PhoneForm>({
    resolver: zodResolver(phoneSchema),
    defaultValues: { phone: '+91' },
  });

  // ─── Email form ──────────────────────────────────────────────────────
  const emailForm = useForm<EmailForm>({
    resolver: zodResolver(emailSchema),
  });

  // ─── Mutations ───────────────────────────────────────────────────────
  const sendOtpMutation = useMutation({
    mutationFn: (phone: string) => authApi.sendOtp(phone),
    onSuccess: (_data, phone) => {
      navigate('/verify-otp', { state: { phone } });
    },
  });

  const loginEmailMutation = useMutation({
    mutationFn: (data: EmailForm) => authApi.loginEmail(data.email, data.password),
    onSuccess: (data) => {
      setAccessToken(data.accessToken);
      const payload = jwtDecode<JwtPayload>(data.accessToken);
      dispatch(setUser(payload));
      navigate(from, { replace: true });
    },
  });

  const handlePhoneSubmit = (data: PhoneForm): void => {
    // Normalise phone: ensure + prefix
    const phone = data.phone.startsWith('+') ? data.phone : `+${data.phone}`;
    sendOtpMutation.mutate(phone);
  };

  const handleEmailSubmit = (data: EmailForm): void => {
    loginEmailMutation.mutate(data);
  };

  const serverError =
    (sendOtpMutation.error as { response?: { data?: { error?: { message?: string } } } })?.response
      ?.data?.error?.message ??
    (loginEmailMutation.error as { response?: { data?: { error?: { message?: string } } } })
      ?.response?.data?.error?.message;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="space-y-2">
        <h1 className="text-2xl font-bold tracking-tight text-foreground">Welcome back</h1>
        <p className="text-sm text-muted-foreground">Sign in to continue to SHIFTLY</p>
      </div>

      {/* Mode Toggle */}
      <div className="flex gap-1 rounded-lg border border-border bg-muted/50 p-1">
        <button
          type="button"
          onClick={() => setMode('phone')}
          className={`flex flex-1 items-center justify-center gap-2 rounded-md py-2 text-sm font-medium transition-all duration-200 ${
            mode === 'phone'
              ? 'bg-background text-foreground shadow-sm'
              : 'text-muted-foreground hover:text-foreground'
          }`}
        >
          <Phone className="h-4 w-4" />
          Phone OTP
        </button>
        <button
          type="button"
          onClick={() => setMode('email')}
          className={`flex flex-1 items-center justify-center gap-2 rounded-md py-2 text-sm font-medium transition-all duration-200 ${
            mode === 'email'
              ? 'bg-background text-foreground shadow-sm'
              : 'text-muted-foreground hover:text-foreground'
          }`}
        >
          <Mail className="h-4 w-4" />
          Email
        </button>
      </div>

      {/* Forms */}
      <AnimatePresence mode="wait">
        {mode === 'phone' ? (
          <motion.form
            key="phone-form"
            initial={{ opacity: 0, x: -12 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 12 }}
            transition={{ duration: 0.2 }}
            onSubmit={phoneForm.handleSubmit(handlePhoneSubmit)}
            className="space-y-4"
            aria-label="Phone OTP login form"
            noValidate
          >
            <div className="space-y-1.5">
              <label htmlFor="phone" className="text-sm font-medium text-foreground">
                Phone number
              </label>
              <div className="relative">
                <Phone className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <input
                  id="phone"
                  type="tel"
                  autoComplete="tel"
                  autoFocus
                  placeholder="+91 98765 43210"
                  className="input-glow w-full rounded-lg border border-input bg-background py-2.5 pl-10 pr-4 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none disabled:cursor-not-allowed disabled:opacity-50"
                  {...phoneForm.register('phone')}
                />
              </div>
              {phoneForm.formState.errors.phone && (
                <p className="text-xs text-destructive" role="alert">
                  {phoneForm.formState.errors.phone.message}
                </p>
              )}
            </div>

            {serverError && mode === 'phone' && (
              <div className="rounded-lg border border-destructive/20 bg-destructive/10 px-4 py-3">
                <p className="text-sm text-destructive">{serverError}</p>
              </div>
            )}

            <button
              type="submit"
              disabled={sendOtpMutation.isPending}
              className="flex w-full items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-brand transition-all hover:-translate-y-0.5 hover:bg-primary/90 hover:shadow-lg active:translate-y-0 disabled:cursor-not-allowed disabled:opacity-50 disabled:hover:translate-y-0"
            >
              {sendOtpMutation.isPending ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Sending OTP...
                </>
              ) : (
                <>
                  Send OTP
                  <ArrowRight className="h-4 w-4" />
                </>
              )}
            </button>

            <p className="text-center text-xs text-muted-foreground">
              We'll send a 6-digit code to verify your number
            </p>
          </motion.form>
        ) : (
          <motion.form
            key="email-form"
            initial={{ opacity: 0, x: 12 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -12 }}
            transition={{ duration: 0.2 }}
            onSubmit={emailForm.handleSubmit(handleEmailSubmit)}
            className="space-y-4"
            aria-label="Email login form"
            noValidate
          >
            <div className="space-y-1.5">
              <label htmlFor="email" className="text-sm font-medium text-foreground">
                Email address
              </label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <input
                  id="email"
                  type="email"
                  autoComplete="email"
                  autoFocus
                  placeholder="name@company.com"
                  className="input-glow w-full rounded-lg border border-input bg-background py-2.5 pl-10 pr-4 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
                  {...emailForm.register('email')}
                />
              </div>
              {emailForm.formState.errors.email && (
                <p className="text-xs text-destructive" role="alert">
                  {emailForm.formState.errors.email.message}
                </p>
              )}
            </div>

            <div className="space-y-1.5">
              <div className="flex items-center justify-between">
                <label htmlFor="password" className="text-sm font-medium text-foreground">
                  Password
                </label>
                <button
                  type="button"
                  className="text-xs text-primary transition-colors hover:text-primary/80"
                >
                  Forgot password?
                </button>
              </div>
              <div className="relative">
                <input
                  id="password"
                  type={showPassword ? 'text' : 'password'}
                  autoComplete="current-password"
                  placeholder="••••••••"
                  className="input-glow w-full rounded-lg border border-input bg-background px-4 py-2.5 pr-10 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
                  {...emailForm.register('password')}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground transition-colors hover:text-foreground"
                  aria-label={showPassword ? 'Hide password' : 'Show password'}
                >
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
              {emailForm.formState.errors.password && (
                <p className="text-xs text-destructive" role="alert">
                  {emailForm.formState.errors.password.message}
                </p>
              )}
            </div>

            {serverError && mode === 'email' && (
              <div className="rounded-lg border border-destructive/20 bg-destructive/10 px-4 py-3">
                <p className="text-sm text-destructive">{serverError}</p>
              </div>
            )}

            <button
              type="submit"
              disabled={loginEmailMutation.isPending}
              className="flex w-full items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-brand transition-all hover:-translate-y-0.5 hover:bg-primary/90 hover:shadow-lg active:translate-y-0 disabled:cursor-not-allowed disabled:opacity-50"
            >
              {loginEmailMutation.isPending ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Signing in...
                </>
              ) : (
                <>
                  Sign in
                  <ArrowRight className="h-4 w-4" />
                </>
              )}
            </button>
          </motion.form>
        )}
      </AnimatePresence>

      {/* Divider */}
      <div className="relative">
        <div className="absolute inset-0 flex items-center">
          <span className="w-full border-t border-border" />
        </div>
        <div className="relative flex justify-center text-xs uppercase">
          <span className="bg-background px-2 text-muted-foreground">New to SHIFTLY?</span>
        </div>
      </div>

      {/* Register link */}
      <Link
        to="/register"
        className="flex w-full items-center justify-center rounded-lg border border-input bg-background px-4 py-2.5 text-sm font-medium text-foreground transition-colors hover:bg-accent hover:text-accent-foreground"
      >
        Create an account
      </Link>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useLocation, Navigate } from 'react-router-dom';
import { useMutation } from '@tanstack/react-query';
import { Loader2, ArrowRight, ArrowLeft } from 'lucide-react';
import { useAppDispatch } from '@/app/store';
import { setUser } from '../store/authSlice';
import { authApi } from '../api/auth.api';
import { setAccessToken } from '@/shared/lib/api';
import { jwtDecode } from '../utils/jwt';
import type { JwtPayload } from '@shiftly/shared-types';

export default function OtpPage(): React.ReactElement {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const phone = (location.state as { phone?: string })?.phone;

  const [otp, setOtp] = useState<string[]>(Array(6).fill(''));
  const [countdown, setCountdown] = useState(30);
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  // If accessed directly without phone, send back to login
  if (!phone) {
    return <Navigate to="/login" replace />;
  }

  // ─── Countdown Timer ───────────────────────────────────────────────────
  useEffect(() => {
    if (countdown > 0) {
      const timerId = setTimeout(() => setCountdown(countdown - 1), 1000);
      return () => clearTimeout(timerId);
    }
  }, [countdown]);

  // ─── Mutations ─────────────────────────────────────────────────────────
  const verifyOtpMutation = useMutation({
    mutationFn: (code: string) => authApi.verifyOtp(phone, code),
    onSuccess: (data) => {
      setAccessToken(data.accessToken);
      const payload = jwtDecode<JwtPayload>(data.accessToken);
      dispatch(setUser(payload));

      if (data.isNewUser) {
        navigate('/register', { replace: true });
      } else {
        navigate('/dashboard', { replace: true });
      }
    },
  });

  const resendOtpMutation = useMutation({
    mutationFn: () => authApi.sendOtp(phone),
    onSuccess: () => {
      setCountdown(30);
      setOtp(Array(6).fill(''));
      inputRefs.current[0]?.focus();
    },
  });

  // ─── Handlers ──────────────────────────────────────────────────────────
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>, index: number) => {
    const value = e.target.value;
    if (!/^\d*$/.test(value)) return;

    const newOtp = [...otp];
    // Take only the last character if multiple are pasted/typed
    newOtp[index] = value.substring(value.length - 1);
    setOtp(newOtp);

    // Auto-focus next input
    if (value && index < 5) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>, index: number) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLInputElement>) => {
    e.preventDefault();
    const pastedData = e.clipboardData.getData('text').slice(0, 6).split('');
    const newOtp = [...otp];

    pastedData.forEach((char, i) => {
      if (/^\d$/.test(char) && i < 6) {
        newOtp[i] = char;
      }
    });

    setOtp(newOtp);
    const focusIndex = Math.min(pastedData.length, 5);
    inputRefs.current[focusIndex]?.focus();
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const code = otp.join('');
    if (code.length === 6) {
      verifyOtpMutation.mutate(code);
    }
  };

  const serverError = (verifyOtpMutation.error as any)?.response?.data?.error?.message;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="space-y-2">
        <button
          onClick={() => navigate('/login', { replace: true })}
          className="mb-4 flex items-center text-xs font-medium text-muted-foreground transition-colors hover:text-foreground"
        >
          <ArrowLeft className="mr-1 h-3 w-3" />
          Back to login
        </button>
        <h1 className="text-2xl font-bold tracking-tight text-foreground">Verify your number</h1>
        <p className="text-sm text-muted-foreground">
          We sent a 6-digit code to <span className="font-semibold text-foreground">{phone}</span>
        </p>
      </div>

      {/* Form */}
      <form onSubmit={handleSubmit} className="space-y-6" aria-label="OTP Verification form">
        <div className="flex justify-between gap-2">
          {otp.map((digit, index) => (
            <input
              key={index}
              ref={(el) => (inputRefs.current[index] = el)}
              type="text"
              inputMode="numeric"
              pattern="\d*"
              maxLength={1}
              value={digit}
              onChange={(e) => handleChange(e, index)}
              onKeyDown={(e) => handleKeyDown(e, index)}
              onPaste={handlePaste}
              className="input-glow h-14 w-12 rounded-lg border border-input bg-background text-center text-xl font-bold text-foreground transition-all focus:border-ring focus:outline-none"
              autoFocus={index === 0}
              disabled={verifyOtpMutation.isPending}
            />
          ))}
        </div>

        {serverError && (
          <div className="rounded-lg border border-destructive/20 bg-destructive/10 px-4 py-3">
            <p className="text-sm text-destructive">{serverError}</p>
          </div>
        )}

        <button
          type="submit"
          disabled={otp.join('').length !== 6 || verifyOtpMutation.isPending}
          className="flex w-full items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-brand transition-all hover:-translate-y-0.5 hover:bg-primary/90 hover:shadow-lg active:translate-y-0 disabled:cursor-not-allowed disabled:opacity-50 disabled:hover:translate-y-0"
        >
          {verifyOtpMutation.isPending ? (
            <>
              <Loader2 className="h-4 w-4 animate-spin" />
              Verifying...
            </>
          ) : (
            <>
              Verify & Continue
              <ArrowRight className="h-4 w-4" />
            </>
          )}
        </button>
      </form>

      {/* Resend Logic */}
      <div className="text-center text-sm">
        <span className="text-muted-foreground">Didn't receive the code? </span>
        {countdown > 0 ? (
          <span className="font-medium text-foreground">Resend in {countdown}s</span>
        ) : (
          <button
            onClick={() => resendOtpMutation.mutate()}
            disabled={resendOtpMutation.isPending}
            className="font-semibold text-primary transition-colors hover:text-primary/80 disabled:opacity-50"
          >
            {resendOtpMutation.isPending ? 'Sending...' : 'Resend OTP'}
          </button>
        )}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { motion } from 'framer-motion';
import { Loader2, ArrowRight, UserCircle, Building2, Eye, EyeOff } from 'lucide-react';
import { z } from 'zod';
import { useAppDispatch } from '@/app/store';
import { setUser } from '../store/authSlice';
import { authApi } from '../api/auth.api';
import { setAccessToken } from '@/shared/lib/api';
import { jwtDecode } from '../utils/jwt';
import type { JwtPayload, UserRole } from '@shiftly/shared-types';

const registerSchema = z.object({
  firstName: z.string().min(2, 'First name must be at least 2 characters'),
  lastName: z.string().min(2, 'Last name must be at least 2 characters'),
  email: z.string().email('Enter a valid email address'),
  password: z
    .string()
    .min(8, 'Password must be at least 8 characters')
    .regex(/[A-Z]/, 'Password must contain at least one uppercase letter')
    .regex(/[0-9]/, 'Password must contain at least one number'),
});

type RegisterForm = z.infer<typeof registerSchema>;

export default function RegisterPage(): React.ReactElement {
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [role, setRole] = useState<UserRole>('WORKER');
  const [showPassword, setShowPassword] = useState(false);

  const form = useForm<RegisterForm>({
    resolver: zodResolver(registerSchema),
  });

  const registerMutation = useMutation({
    mutationFn: (data: RegisterForm) =>
      authApi.register({
        email: data.email,
        password: data.password,
        firstName: data.firstName,
        lastName: data.lastName,
        role: role,
      }),
    onSuccess: (data) => {
      setAccessToken(data.accessToken);
      const payload = jwtDecode<JwtPayload>(data.accessToken);
      dispatch(setUser(payload));
      navigate('/onboarding', { replace: true });
    },
  });

  const onSubmit = (data: RegisterForm) => {
    registerMutation.mutate(data);
  };

  const serverError = (registerMutation.error as any)?.response?.data?.error?.message;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="space-y-2">
        <h1 className="text-2xl font-bold tracking-tight text-foreground">Create an account</h1>
        <p className="text-sm text-muted-foreground">Join SHIFTLY to find work or hire talent</p>
      </div>

      {/* Role Selection */}
      <div className="grid grid-cols-2 gap-3">
        <button
          type="button"
          onClick={() => setRole('WORKER')}
          className={`flex flex-col items-center justify-center rounded-xl border-2 p-4 transition-all duration-200 ${
            role === 'WORKER'
              ? 'border-primary bg-primary/5 text-primary'
              : 'border-border bg-background text-muted-foreground hover:border-primary/50'
          }`}
        >
          <UserCircle className="mb-2 h-6 w-6" />
          <span className="text-sm font-semibold">I'm a Worker</span>
        </button>
        <button
          type="button"
          onClick={() => setRole('EMPLOYER')}
          className={`flex flex-col items-center justify-center rounded-xl border-2 p-4 transition-all duration-200 ${
            role === 'EMPLOYER' || role === 'RECRUITER'
              ? 'border-primary bg-primary/5 text-primary'
              : 'border-border bg-background text-muted-foreground hover:border-primary/50'
          }`}
        >
          <Building2 className="mb-2 h-6 w-6" />
          <span className="text-sm font-semibold">I'm an Employer</span>
        </button>
      </div>

      {/* Register Form */}
      <motion.form
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="space-y-4"
        onSubmit={form.handleSubmit(onSubmit)}
        noValidate
      >
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1.5">
            <label htmlFor="firstName" className="text-sm font-medium text-foreground">
              First name
            </label>
            <input
              id="firstName"
              placeholder="John"
              className="input-glow w-full rounded-lg border border-input bg-background px-4 py-2.5 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
              {...form.register('firstName')}
            />
            {form.formState.errors.firstName && (
              <p className="text-xs text-destructive">{form.formState.errors.firstName.message}</p>
            )}
          </div>
          <div className="space-y-1.5">
            <label htmlFor="lastName" className="text-sm font-medium text-foreground">
              Last name
            </label>
            <input
              id="lastName"
              placeholder="Doe"
              className="input-glow w-full rounded-lg border border-input bg-background px-4 py-2.5 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
              {...form.register('lastName')}
            />
            {form.formState.errors.lastName && (
              <p className="text-xs text-destructive">{form.formState.errors.lastName.message}</p>
            )}
          </div>
        </div>

        <div className="space-y-1.5">
          <label htmlFor="email" className="text-sm font-medium text-foreground">
            Email address
          </label>
          <input
            id="email"
            type="email"
            placeholder="john@example.com"
            className="input-glow w-full rounded-lg border border-input bg-background px-4 py-2.5 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
            {...form.register('email')}
          />
          {form.formState.errors.email && (
            <p className="text-xs text-destructive">{form.formState.errors.email.message}</p>
          )}
        </div>

        <div className="space-y-1.5">
          <label htmlFor="password" className="text-sm font-medium text-foreground">
            Password
          </label>
          <div className="relative">
            <input
              id="password"
              type={showPassword ? 'text' : 'password'}
              placeholder="Create a strong password"
              className="input-glow w-full rounded-lg border border-input bg-background px-4 py-2.5 pr-10 text-sm text-foreground placeholder:text-muted-foreground focus:border-ring focus:outline-none"
              {...form.register('password')}
            />
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground transition-colors hover:text-foreground"
            >
              {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
            </button>
          </div>
          {form.formState.errors.password && (
            <p className="text-xs text-destructive">{form.formState.errors.password.message}</p>
          )}
        </div>

        {serverError && (
          <div className="rounded-lg border border-destructive/20 bg-destructive/10 px-4 py-3">
            <p className="text-sm text-destructive">{serverError}</p>
          </div>
        )}

        <button
          type="submit"
          disabled={registerMutation.isPending}
          className="flex w-full items-center justify-center gap-2 rounded-lg bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-brand transition-all hover:-translate-y-0.5 hover:bg-primary/90 hover:shadow-lg active:translate-y-0 disabled:cursor-not-allowed disabled:opacity-50"
        >
          {registerMutation.isPending ? (
            <>
              <Loader2 className="h-4 w-4 animate-spin" />
              Creating account...
            </>
          ) : (
            <>
              Create account
              <ArrowRight className="h-4 w-4" />
            </>
          )}
        </button>

        <p className="px-4 text-center text-xs text-muted-foreground">
          By clicking create account, you agree to our{' '}
          <Link to="/terms" className="underline hover:text-foreground">
            Terms of Service
          </Link>{' '}
          and{' '}
          <Link to="/privacy" className="underline hover:text-foreground">
            Privacy Policy
          </Link>
          .
        </p>
      </motion.form>

      <div className="text-center text-sm">
        <span className="text-muted-foreground">Already have an account? </span>
        <Link
          to="/login"
          className="font-semibold text-primary transition-colors hover:text-primary/80"
        >
          Sign in
        </Link>
      </div>
    </div>
  );
}

import api from '@/shared/lib/api';

export interface SubscriptionData {
  id: string;
  userId: string;
  plan: string;
  status: string;
  currentPeriodStart: string;
  currentPeriodEnd: string;
}

export interface InvoiceData {
  id: string;
  date: string;
  amount: string;
  status: string;
  plan: string;
}

export const subscriptionsApi = {
  getCurrentSubscription: async (): Promise<SubscriptionData> => {
    const { data } = await api.get('/subscriptions/current');
    return data;
  },

  getInvoices: async (): Promise<InvoiceData[]> => {
    const { data } = await api.get('/subscriptions/invoices');
    return data;
  },

  upgradePlan: async (plan: string): Promise<SubscriptionData> => {
    const { data } = await api.post('/subscriptions/upgrade', { plan });
    return data;
  },
};

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { Download, Receipt, CheckCircle2, X, Plus, AlertCircle } from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { subscriptionsApi } from '../api/subscriptions.api';

const PLANS = [
  {
    id: 'FREE',
    name: 'Free',
    price: '₹0',
    description: 'Up to 5 active jobs, Basic analytics',
    color: 'border-border',
  },
  {
    id: 'PROFESSIONAL',
    name: 'Professional',
    price: '₹4,999',
