import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { shiftsApi } from '../../jobs/api/shifts.api';
import { format } from 'date-fns';
import { ReviewModal } from '@/features/reviews/components/ReviewModal';

export function TimesheetApprovalPage() {
  const queryClient = useQueryClient();
  const [reviewModalData, setReviewModalData] = useState<{
    isOpen: boolean;
    jobId: string;
    revieweeId: string;
  } | null>(null);

  const { data: timesheets, isLoading } = useQuery({
    queryKey: ['employer-timesheets'],
    queryFn: shiftsApi.getEmployerTimesheets,
  });

  const approveMutation = useMutation({
    mutationFn: shiftsApi.approveTimesheet,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['employer-timesheets'] });
    },
  });

  const rejectMutation = useMutation({
    mutationFn: ({ id, reason }: { id: string; reason: string }) =>
      shiftsApi.rejectTimesheet(id, reason),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['employer-timesheets'] });
    },
  });

  if (isLoading) {
    return <div className="p-8 text-center text-muted-foreground">Loading timesheets...</div>;
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight text-foreground">Timesheet Approvals</h1>
        <p className="mt-1 text-muted-foreground">
          Review and approve completed shifts from workers.
        </p>
      </div>

      <div className="overflow-hidden rounded-xl border border-border bg-card shadow-sm">
        {!timesheets || timesheets.length === 0 ? (
          <div className="p-12 text-center text-muted-foreground">
            No timesheets pending review.
          </div>
        ) : (
          <div className="divide-y divide-border">
            {timesheets.map((ts: any) => (
              <div
                key={ts.id}
                className="flex flex-col justify-between gap-6 p-6 transition-colors hover:bg-muted/30 md:flex-row md:items-center"
              >
                <div className="flex items-start gap-4">
                  <div className="flex h-10 w-10 items-center justify-center rounded-full bg-primary/10 font-bold text-primary">
                    {ts.shift.worker.user.email?.charAt(0).toUpperCase() || 'W'}
                  </div>
                  <div>
                    <h3 className="font-semibold text-foreground">
                      {ts.shift.job.title} - {ts.shift.worker.user.email}
                    </h3>
                    <div className="mt-1 space-y-1 text-sm text-muted-foreground">
                      <p>
                        Hours Worked:{' '}
                        <span className="font-medium text-foreground">{ts.hoursWorked}h</span>
                      </p>
                      <p>Date: {format(new Date(ts.shift.scheduledStart), 'MMM d, yyyy')}</p>
                      {ts.notes && <p className="text-xs italic">Note: {ts.notes}</p>}
                    </div>
                  </div>
                </div>

                <div className="flex flex-col items-end gap-2">
                  <span
                    className={`rounded-full border px-2.5 py-0.5 text-xs font-medium ${
                      ts.status === 'APPROVED'
                        ? 'border-green-500/20 bg-green-500/10 text-green-500'
                        : ts.status === 'REJECTED'
                          ? 'border-red-500/20 bg-red-500/10 text-red-500'
                          : 'border-amber-500/20 bg-amber-500/10 text-amber-500'
                    }`}
                  >
                    {ts.status}
                  </span>

                  {ts.status === 'SUBMITTED' && (
                    <div className="mt-2 flex items-center gap-2">
                      <button
                        onClick={() => {
                          const reason = prompt('Reason for rejection:');
                          if (reason) {
                            rejectMutation.mutate({ id: ts.id, reason });
                          }
                        }}
                        className="rounded-lg border border-border px-3 py-1.5 text-sm font-medium text-foreground transition-colors hover:bg-muted"
                      >
                        Reject
                      </button>
                      <button
                        onClick={() => approveMutation.mutate(ts.id)}
                        className="rounded-lg bg-primary px-3 py-1.5 text-sm font-medium text-primary-foreground shadow-sm transition-colors hover:bg-primary/90"
                      >
                        Approve
                      </button>
                    </div>
                  )}

                  {ts.status === 'APPROVED' && (
                    <button
                      onClick={() =>
                        setReviewModalData({
                          isOpen: true,
                          jobId: ts.shift.jobId,
                          revieweeId: ts.shift.workerId,
                        })
                      }
                      className="mt-2 text-xs font-medium text-primary hover:underline"
                    >
                      Leave a Review
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {reviewModalData && (
        <ReviewModal
          isOpen={reviewModalData.isOpen}
          jobId={reviewModalData.jobId}
          revieweeId={reviewModalData.revieweeId}
          targetType="WORKER"
          onClose={() => setReviewModalData(null)}
        />
      )}
    </div>
  );
}

import api from '../../../shared/lib/api';
import type { Wallet, Transaction } from '@shiftly/shared-types';

export const walletApi = {
  getWallet: async (): Promise<Wallet> => {
    const response = await api.get('/wallets/me');
    return response.data.data;
  },

  getTransactions: async (): Promise<Transaction[]> => {
    const response = await api.get('/wallets/me/transactions');
    return response.data.data ?? [];
  },

  topUp: async (amount: number): Promise<Wallet> => {
    const response = await api.post('/wallets/topup', { amount });
    return response.data.data;
  },

  withdraw: async (amount: number): Promise<Wallet> => {
    const response = await api.post('/wallets/withdraw', { amount });
    return response.data.data;
  },
};

import { useState } from 'react';
import { ArrowUpRight, ArrowDownLeft, Clock, Wallet as WalletIcon, Lock } from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { walletApi } from '../api/wallet.api';
import { format } from 'date-fns';

/** Format a number as INR currency */
function formatINR(amount: number): string {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 2,
  }).format(amount);
}

export default function WalletPage() {
  const queryClient = useQueryClient();
  const [topUpAmount, setTopUpAmount] = useState('');
  const [withdrawAmount, setWithdrawAmount] = useState('');

  const { data: wallet, isLoading: isWalletLoading } = useQuery({
    queryKey: ['wallet'],
    queryFn: walletApi.getWallet,
  });

  const { data: transactions, isLoading: isTxLoading } = useQuery({
    queryKey: ['transactions'],
    queryFn: walletApi.getTransactions,
  });

  const topUpMutation = useMutation({
    mutationFn: (amount: number) => walletApi.topUp(amount),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['wallet'] });
      queryClient.invalidateQueries({ queryKey: ['transactions'] });
      setTopUpAmount('');
      alert('Top up successful!');
    },
    onError: (err: any) => {
      alert(err.response?.data?.message || 'Failed to top up');
    },
  });

  const withdrawMutation = useMutation({
    mutationFn: (amount: number) => walletApi.withdraw(amount),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['wallet'] });
      queryClient.invalidateQueries({ queryKey: ['transactions'] });
      setWithdrawAmount('');
      alert('Withdrawal successful!');
    },
    onError: (err: any) => {
      alert(err.response?.data?.message || 'Failed to withdraw');
    },
  });

  if (isWalletLoading || isTxLoading) {
    return <div className="p-8 text-center text-muted-foreground">Loading wallet...</div>;
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight text-foreground">Wallet & Payments</h1>
        <p className="mt-1 text-muted-foreground">
          Manage your funds, view transactions, and handle payouts.
        </p>
      </div>

      <div className="grid grid-cols-1 gap-6 md:grid-cols-3">
        <div className="space-y-6 md:col-span-2">
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            {/* Main Balance Card */}
            <div className="relative overflow-hidden rounded-2xl bg-gradient-to-br from-primary to-primary/80 p-6 text-primary-foreground shadow-lg">
              <div className="absolute right-0 top-0 p-4 opacity-20 pointer-events-none">
                <WalletIcon className="h-24 w-24" />
              </div>
              <div className="relative z-10">
                <p className="mb-1 font-medium text-primary-foreground/80">Available Balance</p>
                <h2 className="text-4xl font-bold tracking-tight">
                  {formatINR(Number(wallet?.balance || 0))}
                </h2>
                <div className="mt-6 flex gap-3">
                  <div className="flex-1">
                    <input
                      type="text"
                      inputMode="numeric"
                      placeholder="Amount (₹)"
                      className="w-full rounded-lg border-0 bg-white/90 px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-white/50"
                      value={topUpAmount}
                      onChange={(e) => setTopUpAmount(e.target.value.replace(/[^0-9.]/g, ''))}
                    />
                  </div>
                  <button
                    onClick={() => topUpAmount && topUpMutation.mutate(Number(topUpAmount))}
                    disabled={topUpMutation.isPending || !topUpAmount || Number(topUpAmount) <= 0}
                    className="flex items-center justify-center rounded-lg bg-white/20 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-white/30 disabled:opacity-50"
                  >
                    {topUpMutation.isPending ? '...' : 'Top Up'}
                  </button>
                </div>
              </div>
            </div>

            {/* Escrow Balance Card */}
            <div className="flex flex-col justify-between rounded-2xl border border-border bg-card p-6 shadow-sm">
              <div>
                <div className="mb-1 flex items-center gap-2 font-medium text-muted-foreground">
                  <Lock className="h-4 w-4" />
                  <span>In Escrow</span>
                </div>
                <h2 className="text-3xl font-bold tracking-tight text-foreground">
                  {formatINR(Number(wallet?.escrowBalance || 0))}
                </h2>
                <p className="mt-2 text-xs text-muted-foreground">Funds locked for active jobs</p>
              </div>
              <div className="mt-6 flex gap-3">
                <div className="flex-1">
                  <input
                    type="text"
                    inputMode="numeric"
                    placeholder="Amount (₹)"
                    className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm text-foreground outline-none focus:ring-2 focus:ring-primary"
                    value={withdrawAmount}
                    onChange={(e) => setWithdrawAmount(e.target.value.replace(/[^0-9.]/g, ''))}
                  />
                </div>
                <button
                  onClick={() => withdrawAmount && withdrawMutation.mutate(Number(withdrawAmount))}
                  disabled={
                    withdrawMutation.isPending || !withdrawAmount || Number(withdrawAmount) <= 0
                  }
                  className="flex items-center justify-center rounded-lg bg-secondary px-4 py-2 text-sm font-medium text-secondary-foreground transition-colors hover:bg-secondary/80 disabled:opacity-50"
                >
                  {withdrawMutation.isPending ? '...' : 'Withdraw'}
                </button>
              </div>
            </div>
          </div>

          {/* Transactions List */}
          <div className="overflow-hidden rounded-xl border border-border bg-card shadow-sm">
            <div className="flex items-center justify-between border-b border-border p-4">
              <h3 className="font-semibold text-foreground">Recent Transactions</h3>
            </div>

            <div className="divide-y divide-border">
              {!transactions || transactions.length === 0 ? (
                <div className="p-8 text-center text-muted-foreground">No recent transactions</div>
              ) : (
                transactions.map((tx: any) => (
                  <div
                    key={tx.id}
                    className="flex items-center justify-between p-4 transition-colors hover:bg-muted/30"
                  >
                    <div className="flex items-center gap-4">
                      <div
                        className={`flex h-10 w-10 items-center justify-center rounded-full ${
                          tx.type === 'TOPUP' || tx.type === 'ESCROW_RELEASE'
                            ? 'bg-green-500/10 text-green-500'
                            : tx.type === 'WITHDRAWAL'
                              ? 'bg-blue-500/10 text-blue-500'
                              : tx.type === 'ESCROW_LOCK'
                                ? 'bg-orange-500/10 text-orange-500'
                                : 'bg-muted text-muted-foreground'
                        }`}
                      >
                        {tx.type === 'TOPUP' || tx.type === 'ESCROW_RELEASE' ? (
                          <ArrowDownLeft className="h-5 w-5" />
                        ) : tx.type === 'WITHDRAWAL' ? (
                          <ArrowUpRight className="h-5 w-5" />
                        ) : (
                          <Lock className="h-5 w-5" />
                        )}
                      </div>
                      <div>
                        <p className="font-medium text-foreground">{tx.description}</p>
                        <p className="mt-0.5 flex items-center gap-1 text-sm text-muted-foreground">
                          <Clock className="h-3 w-3" />
                          {format(new Date(tx.createdAt), 'MMM d, h:mm a')}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p
                        className={`font-semibold ${
                          tx.type === 'TOPUP' || tx.type === 'ESCROW_RELEASE'
                            ? 'text-green-500'
                            : 'text-foreground'
                        }`}
                      >
                        {tx.type === 'TOPUP' || tx.type === 'ESCROW_RELEASE' ? '+' : '-'}
                        {formatINR(Number(tx.amount))}
                      </p>
                      <p
                        className={`mt-1 text-xs font-medium ${
                          tx.status === 'COMPLETED'
                            ? 'text-green-500'
                            : tx.status === 'PENDING'
                              ? 'text-amber-500'
                              : 'text-red-500'
                        }`}
                      >
                        {tx.status}
                      </p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

